import json

# Check all symbols for their date ranges
symbols = ['AGMH', 'AMTX', 'APEX', 'BIOC', 'BKYI', 'CBAT', 'CCCL', 'CORV', 'CPAH', 'DZSI', 'FAMI', 'FTFT', 'FTR', 'IDEX', 'ISDS', 'MCEP', 'NXTD', 'OPTT', 'PEIX', 'RBZ', 'SES', 'SNSS', 'SPI', 'SYPR', 'VTIQW']

results = {}

for symbol in symbols:
    query = f'SELECT MIN(Date) as min_date, MAX(Date) as max_date FROM "{symbol}"'
    result = query_db(db_name="stocktrade_database", query=query)

    # Handle result from query_db
    if isinstance(result, str) and result.endswith('.json'):
        with open(result, 'r') as f:
            data = json.load(f)
    else:
        data = result

    if data and len(data) > 0:
        min_date = data[0].get('min_date')
        max_date = data[0].get('max_date')
        results[symbol] = {'min_date': min_date, 'max_date': max_date}

print('__RESULT__:')
print(json.dumps(results))

