import json

# Get company info
troubled_companies = locals()['var_functions.query_db:68']

# Create a dictionary of symbol to company info
company_info = {}
status_desc_map = {
    'D': 'Deficient',
    'E': 'Delinquent', 
    'G': 'Deficient and bankrupt',
    'H': 'Deficient and delinquent',
    'J': 'Delinquent and bankrupt',
    'K': 'Deficient, delinquent, and bankrupt'
}

for item in troubled_companies:
    symbol = item['Symbol']
    desc = item['Company Description']
    fin_status = item['Financial Status']

    # Extract company name more cleanly
    company_name = desc.split(',')[0].split(' specializes')[0].split(' is')[0].strip()

    # Override specific ones for better formatting
    if symbol == 'FTR':
        company_name = 'Frontier Communications Corporation'
    elif symbol == 'CBAT':
        company_name = 'CBAK Energy Technology Inc'
    elif symbol == 'RBZ':
        company_name = 'Reebonz Holding Limited'
    elif symbol == 'BKYI':
        company_name = 'BIO-key International Inc'
    elif symbol == 'APEX':
        company_name = 'Apex Global Brands Inc'
    elif symbol == 'ISDS':
        company_name = 'Invesco RAFI Strategic ETF'
    elif symbol == 'VTIQW':
        company_name = 'VectoIQ Acquisition Corp'

    company_info[symbol] = {
        'company_name': company_name,
        'financial_status': status_desc_map.get(fin_status, 'Unknown')
    }

print('__RESULT__:')
print(json.dumps(company_info))

